def merge_ranges(pairs):
    if not pairs:
        return []

    pairs.sort(key=lambda x: x[0])
    merged = [pairs[0]]

    for pair in pairs[1:]:
        if pair[0] <= merged[-1][1]:
            merged[-1][1] = max(merged[-1][1], pair[1])
        else:
            merged.append(pair)

    return merged
